#include <bits/stdc++.h>
using namespace std;

long long solve(string s, vector<long long> order, long long k) {
    int n = s.length();
    long long total_substrings = n * (n + 1LL) / 2;
    long long invalid_substrings = total_substrings;
    set<int> stars;
    for (int t = 0; t < n; ++t) {
        int pos = order[t];
        auto it = stars.lower_bound(pos);
        int predecessor = -1;
        if (it != stars.begin()) {
            predecessor = *(it - 1);
        }
        int successor = n;
        if (it != stars.end()) {
            successor = *it;
        }
        int length = successor - predecessor - 1;
        long long original_contribution = (long long)length * (length + 1) / 2;
        int l = pos - predecessor - 1;
        int r = successor - pos - 1;
        long long new_contribution = (long long)(l * (l + 1) / 2) + (long long)(r * (r + 1) / 2);
        long long delta = original_contribution - new_contribution;
        invalid_substrings -= delta;
        stars.insert(pos);
        long long current_valid = total_substrings - invalid_substrings;
        if (current_valid >= k) {
            return t;
        }
    }
    return -1;
}
